            ContentJson = """{"title":"Asset Acquisition & Accounting","groups":[{"heading":"Where to Find It","items":[{"label":"Location","value":"The Acquisition section sits below the core identity fields (name, type, location, manufacturer, model, serial, notes) in the Add Asset dialog."},{"label":"Applies to","value":"EVERY asset type — Machine, Tooling, Facility, Vehicle, Other. This is separate from the Tooling-only fields, which appear only when Type = Tooling."},{"label":"When to fill it","value":"At acquisition time, when you register the asset. All four fields are optional, so you can leave them blank and add them later via Edit."}]},{"heading":"The Four Fields","items":[{"label":"Acquisition Cost","value":"What the asset cost to acquire. Number input. Must be ≥ 0 and ≤ 1,000,000,000 — out-of-range values block Save. data-testid: asset-acquisition-cost"},{"label":"Depreciation Method","value":"How the asset's value is written down over time. Options: Straight Line, Declining Balance, Units of Production, or — (none). These match the server enum exactly. data-testid: asset-depreciation-method"},{"label":"Work Center","value":"The station/work center the asset operates at, entered as a work-center ID (number). Links the asset to where it physically runs. data-testid: asset-work-center-id"},{"label":"GL Account","value":"The general-ledger account the asset maps to (text). data-testid: asset-gl-account"}]},{"heading":"GL Account & the Accounting Boundary","items":[{"label":"Integrated mode","value":"When an external accounting provider (e.g., QuickBooks) is connected, the GL account is populated by the accounting sync — you don't type it."},{"label":"Standalone mode","value":"With no accounting provider connected, you enter the GL account manually."},{"label":"Depreciation schedules","value":"The app stores the depreciation METHOD on the asset but does not compute full depreciation schedules — that stays in your accounting system. The method here is informational/for export."}]},{"heading":"Editing Later","items":[{"label":"How to change them","value":"Open the asset (click its row), click the pencil/Edit icon, update the values, and Save. The same dialog is reused for create and edit."},{"label":"Common mistake","value":"Assuming cost/depreciation fields are tooling-specific. They are not — a forklift or a CNC mill captures acquisition details in exactly the same section."}]}]}"""
